mapper.select:
SELECT ti.id, ti.teacher_id AS teacherId, su.email AS teacherEmail, su.nickname AS teacherName, ti.course_order_id AS courseOrderId, ti.refund_id AS refundId, p.name_i18n_code AS packageName, ti.amount_usd AS amountUsd, ti.type, ti.settled_at AS settledAt, ti.create_time AS createTime FROM teacher_income ti LEFT JOIN system_users su ON su.id = ti.teacher_id AND su.deleted = 0 LEFT JOIN course_order co ON co.id = ti.course_order_id AND co.deleted = 0 LEFT JOIN student_package sp ON sp.id = co.student_package_id AND sp.deleted = 0 LEFT JOIN package p ON p.id = sp.package_id AND p.deleted = 0 WHERE ti.deleted = 0
AND ti.teacher_id = #{req.teacherId}
AND ti.type = #{req.type}
AND ti.settled_at >= #{req.settledAtFrom}
AND ti.settled_at <= #{req.settledAtTo}
ORDER BY ti.create_time DESC
